using Microsoft.EntityFrameworkCore;
using System.Threading.Tasks;

public class EventBookingContext : DbContext
{
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
        => optionsBuilder.UseSqlServer("Data Source=your_database_connection_string");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
        => modelBuilder.Entity<Ticket>()
            .Property(b => b.QuantityAvailable)
            .HasConversion<int>();
}

public class Ticket
{
    public int Id { get; set; }
    public int QuantityAvailable { get; set; }
}

public async Task<Ticket> PurchaseTicketsAsync(int eventId, int quantity)
{
    var context = new EventBookingContext();

    using (var transactionScope = new TransactionScope(TransactionScopeOption.Required))
    {
        try
        {
            var ticket = await context.Tickets.FindAsync(eventId);

            if (ticket == null || ticket.QuantityAvailable < quantity)
                throw new Exception("Not enough tickets available for this event");

            ticket.QuantityAvailable -= quantity;

            context.SaveChanges();

            transactionScope.Complete();
        }
        catch (Exception ex) when (transactionScope.IsCompleted)
        {
            // Ignore the exception and roll back the transaction
            transactionScope.Dispose();
        }

        return await context.Tickets.FindAsync(eventId);
    }
}